sql_query:
SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Brentuximab-vedotin' AND "Monotherapy/combination" = 'Combination';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Treatment regimen" AS source_value FROM clinical_trials
WHERE "Name of ICI" = 'Brentuximab-vedotin' AND "Monotherapy/combination" = 'Combination'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_added_agents(source_value) AS "added_agents"
FROM base;
